import type { SearchInputConfig } from '@linm-soft-org/linm-web-common-components';
import { getCustomerTypeLabel } from '../../constants/partnerFieldLabels';
import { ktService } from '../../services/kt/ktService';
import type { CustomerDto } from '../../services/kt/models';
import {
  SEARCH_DROPDOWN_CODE_WIDTH,
  SEARCH_DROPDOWN_PORTAL,
  SEARCH_DROPDOWN_PRIMARY_WIDTH,
} from './searchDropdownDefaults';

export type CustomerSearchType = 'Customer' | 'Supplier' | 'Both';

export interface CreateCustomerSearchConfigOptions {
  /** Filter danh mục đối tượng — omit = tất cả loại (Customer + Supplier + Both). */
  customerType?: CustomerSearchType;
}

/** SEARCH_REMOTE — danh mục đối tượng (`GET /master/customers`). */
export function createCustomerSearchConfig(
  options: CreateCustomerSearchConfigOptions = {},
): SearchInputConfig<CustomerDto> {
  const { customerType } = options;

  return {
    api: {
      getItemKey: (c) => c.customerId,
      search: async ({ search, page, pageSize }) => {
        const res = await ktService.searchCustomers({
          search: search?.trim() || undefined,
          page,
          pageSize,
          customerType,
          isActive: true,
        });
        const totalPages = Math.max(1, Math.ceil(res.totalCount / pageSize));
        return {
          items: res.items,
          page: res.page,
          totalPages,
        };
      },
      getDetail: (id) => ktService.getCustomer(id),
    },
    display: {
      getPrimaryDisplay: (c) => c.code,
      getSecondaryDisplay: (c) => c.name,
      getSingleDisplay: (c) => (c.code && c.name ? `${c.code} — ${c.name}` : c.code || c.name),
    },
    columns: [
      { key: 'code', variant: 'badge', width: SEARCH_DROPDOWN_CODE_WIDTH, render: (c) => c.code },
      { key: 'name', variant: 'primary', width: SEARCH_DROPDOWN_PRIMARY_WIDTH, render: (c) => c.name },
      {
        key: 'customerType',
        variant: 'meta',
        width: '6.5rem',
        render: (c) => getCustomerTypeLabel(c.customerType) ?? '',
      },
      {
        key: 'phone',
        variant: 'meta',
        width: '7rem',
        align: 'end',
        icon: 'fas fa-phone',
        visible: (c) => !!c.phone,
        render: (c) => c.phone ?? '',
      },
    ],
    header: {
      columns: [
        { key: 'code', label: 'Mã' },
        { key: 'name', label: 'Tên đối tượng' },
        { key: 'customerType', label: 'Loại' },
        { key: 'phone', label: 'Điện thoại' },
      ],
    },
    texts: {
      secondaryPlaceholder: 'Tên đối tượng',
      empty: 'Không tìm thấy đối tượng',
    },
    ...SEARCH_DROPDOWN_PORTAL,
  };
}

/** NCC / supplier — `customerType=Supplier`. */
export function createSupplierSearchConfig(): SearchInputConfig<CustomerDto> {
  return createCustomerSearchConfig({ customerType: 'Supplier' });
}
